import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ScoreViewerComponent extends Component {
  @tracked selectedMatchId = null
  @tracked scoreData = null

  selectMatch = (matchId) => {
    this.selectedMatchId = matchId
    this.loadScore.perform() // No need to pass matchId — reads from @tracked
  }

  // Task reads from @tracked property via 'this'
  loadScore = task(async () => {
    if (!this.selectedMatchId) return

    const response = await fetch(`/api/matches/${this.selectedMatchId}/score`)
    this.scoreData = await response.json()
  })

  <template>
    <select {{on 'change' (fn this.selectMatch)}}>
      <option value="match-1">Match 1</option>
      <option value="match-2">Match 2</option>
      <option value="match-3">Match 3</option>
    </select>

    {{#if this.scoreData}}
      <p>{{this.scoreData.runs}}/{{this.scoreData.wickets}}</p>
    {{/if}}
  </template>
}
```
Tasks can access `this` (the class instance) freely inside the async function, including any `@tracked` properties. The value of `@tracked` properties is read at the moment the `await` occurs, reflecting the current state of the component — not the state at the time `.perform()` was called.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class TeamRosterComponent extends Component {
  @tracked players = []
  @tracked totalCount = 0
  @tracked lastUpdated = null

  loadRoster = task(async (teamId) => {
    const response = await fetch(`/api/teams/${teamId}/roster`)
    const data = await response.json()

    // Update multiple @tracked properties after task completes
    this.players = data.players
    this.totalCount = data.total
    this.lastUpdated = new Date().toLocaleTimeString()

    return data // Also available via task.last.value
  })

  <template>
