    {{#if this.lastUpdated}}
      <p class="text-xs text-gray-400">Updated: {{this.lastUpdated}}</p>
    {{/if}}

    <p>Players: {{this.totalCount}}</p>
    {{#each this.players as |player|}}
      <p>{{player.name}} — {{player.role}}</p>
    {{/each}}
  </template>
}
