import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class LiveScoreWidgetComponent extends Component {
  @tracked scores = null

  fetchLiveScores = task({ drop: true }, async () => {
    const response = await fetch('https://api.cricketdata.com/v1/live-scores', {
      headers: {
        'Authorization': `Bearer ${this.args.apiKey}`,
        'Accept': 'application/json'
      }
    })

    if (!response.ok) {
      throw new Error(`Score fetch failed: ${response.status}`)
    }

    const data = await response.json()
    this.scores = data.matches.map(m => ({
      matchId: m.id,
      homeTeam: m.home_team,
      awayTeam: m.away_team,
      score: `${m.runs}/${m.wickets}`,
      overs: m.overs
    }))

    return this.scores
  })

  <template>
    <div class="live-scores">
      <button
        {{on 'click' this.fetchLiveScores.perform}}
        disabled={{this.fetchLiveScores.isRunning}}
        class="px-4 py-2 bg-red-600 text-white rounded"
      >
        {{#if this.fetchLiveScores.isRunning}}
          Fetching...
        {{else}}
          🔴 Get Live Scores
        {{/if}}
      </button>

      {{#each this.scores as |match|}}
        <div class="p-2 border-b">
          <span class="font-medium">{{match.homeTeam}} vs {{match.awayTeam}}</span>
          <span class="ml-4 text-green-600">{{match.score}} ({{match.overs}} ov)</span>
        </div>
      {{/each}}
    </div>
  </template>
}
```
This shows a complete fetch workflow: pass auth headers, check `response.ok`, transform the response, and store both in `@tracked` and as a return value. The `drop` modifier prevents concurrent fetches when the user clicks rapidly. Always check `response.ok` before `.json()` to catch HTTP-level errors.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class TournamentPageComponent extends Component {
  @tracked tournament = null
  @tracked fixtures = []
  @tracked topScorers = []

  loadTournamentPage = task(async (tournamentId) => {
    // Step 1: Fetch tournament details
    const tourneyResponse = await fetch(`/api/tournaments/${tournamentId}`)
    if (!tourneyResponse.ok) throw new Error('Tournament not found')
    this.tournament = await tourneyResponse.json()

    // Step 2: Fetch fixtures using tournament data
    const fixturesResponse = await fetch(
      `/api/tournaments/${tournamentId}/fixtures?season=${this.tournament.currentSeason}`
    )
    this.fixtures = await fixturesResponse.json()

    // Step 3: Fetch top scorers
    const scorersResponse = await fetch(
      `/api/tournaments/${tournamentId}/top-scorers?limit=5`
    )
    this.topScorers = await scorersResponse.json()

    return { tournament: this.tournament, fixtures: this.fixtures, topScorers: this.topScorers }
  })

  <template>
    <button {{on 'click' (fn this.loadTournamentPage.perform @tournamentId)}}>
      Load Tournament
    </button>

    {{#if this.loadTournamentPage.isRunning}}
      <p>Loading tournament data...</p>
    {{/if}}

    {{#if this.tournament}}
      <h1>{{this.tournament.name}}</h1>
      <p>Season: {{this.tournament.currentSeason}}</p>
    {{/if}}
  </template>
}
```
Multiple sequential `await fetch()` calls inside a single task run in order, each waiting for the previous to complete. If any step throws (network error or `!response.ok`), the task stops immediately and `task.last.error` is populated. This is cleaner than chaining `.then()` and easier to read than separate tasks for each step.
